import dspy
import vex

class VerifiedChainOfThought(dspy.Module):
    def __init__(self, signature):
        super().__init__()
        self.cot = dspy.ChainOfThought(signature)
        self.vex_client = vex.Client(api_key="your-vex-api-key")

    def forward(self, **kwargs):
        prediction = self.cot(**kwargs)

        # Wrap the output with Vex verification
        verification = self.vex_client.verify(
            module="ChainOfThought",
            inputs=kwargs,
            outputs={
                "rationale": prediction.rationale,
                "answer": prediction.answer
            },
            contracts=[
                vex.Contract(
                    name="answer_non_empty",
                    rule=lambda o: len(o["answer"].strip()) > 0
                ),
                vex.Contract(
                    name="rationale_precedes_answer",
                    rule=lambda o: len(o["rationale"]) > 10
                )
            ]
        )

        if not verification.passed:
            raise vex.VerificationError(
                f"ChainOfThought verification failed: {verification.violations}"
            )

        return prediction

# Usage
qa = VerifiedChainOfThought("question -> answer")
result = qa(question="What is the capital of France?")
